register_filter('shout', str.upper)

@prompt
def greet(name):
    '{{ name | shout }}'

print(greet('world'))

@prompt(filters={'shout': lambda s: s + '!!!'})
def greet2(name):
    '{{ name | shout }}'

print(greet2('world'))  # local filter should win

